// Parse la réponse JSON de Claude — Analyse
const raw = $input.first().json.message?.content?.[0]?.text || $input.first().json.text || '';
const cleaned = raw.replace(/^```json\n?|```$/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: parsed }];
} catch (e) {
  throw new Error('Claude n\'a pas renvoyé du JSON valide pour Analyse: ' + e.message + '\n\nReçu:\n' + raw);
}

// Parse la réponse JSON de Claude — Architecte
const raw = $input.first().json.message?.content?.[0]?.text || $input.first().json.text || '';
const cleaned = raw.replace(/^```json\n?|```$/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: parsed }];
} catch (e) {
  throw new Error('Claude n\'a pas renvoyé du JSON valide pour Architecte: ' + e.message + '\n\nReçu:\n' + raw);
}

// Parse la réponse Claude + transforme en blocks API Notion + crée le tout
const raw = $input.first().json.message?.content?.[0]?.text || $input.first().json.text || '';
const cleaned = raw.replace(/^```json\n?|```$/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Rédacteur: JSON invalide. ' + e.message);
}

// Convertit le format simplifié de Claude en format API Notion
function toNotionBlock(b) {
  const richText = (text) => [{ type: 'text', text: { content: text } }];
  switch (b.type) {
    case 'heading_2':
      return { object: 'block', type: 'heading_2', heading_2: { rich_text: richText(b.text) } };
    case 'heading_3':
      return { object: 'block', type: 'heading_3', heading_3: { rich_text: richText(b.text) } };
    case 'paragraph':
      return { object: 'block', type: 'paragraph', paragraph: { rich_text: richText(b.text) } };
    case 'bulleted_list_item':
      return { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: richText(b.text) } };
    case 'numbered_list_item':
      return { object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: richText(b.text) } };
    case 'callout':
      return {
        object: 'block', type: 'callout',
        callout: {
          icon: { type: 'emoji', emoji: b.icon || '💡' },
          rich_text: richText(b.text)
        }
      };
    case 'quote':
      return { object: 'block', type: 'quote', quote: { rich_text: richText(b.text) } };
    case 'code':
      return { object: 'block', type: 'code', code: { rich_text: richText(b.text), language: 'plain text' } };
    case 'divider':
      return { object: 'block', type: 'divider', divider: {} };
    default:
      return { object: 'block', type: 'paragraph', paragraph: { rich_text: richText(b.text || '') } };
  }
}

// Pour chaque step, génère les children blocks (callout config + content blocks)
const unitData = $('Split Units').item.json;
const stepsForOutput = parsed.steps.map((step) => {
  const configCallout = {
    object: 'block',
    type: 'callout',
    callout: {
      icon: { type: 'emoji', emoji: '⚙️' },
      rich_text: [{ type: 'text', text: { content: 'Config' } }],
      children: [
        { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: `Type : ${step.type === 'step' ? 'étape' : step.type}` } }] } },
        { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: `Durée : ${step.duration_minutes} min` } }] } }
      ]
    }
  };
  const contentBlocks = (step.blocks || []).map(toNotionBlock);
  return {
    title: step.title,
    blocks: [configCallout, ...contentBlocks]
  };
});

return [{
  json: {
    unit_title: unitData.title,
    unit_summary: unitData.summary,
    unit_duration_minutes: unitData.duration_minutes,
    unit_unlock_offset_days: unitData.unlock_offset_days,
    steps: stepsForOutput,
    program_page_id: $('Notion — Create Program Page').item.json.id
  }
}];

// Pour chaque step de la unit, on crée une sub-child page via HTTP Request Notion API
// Ce node prépare les requêtes que le HTTP node fera ensuite
const data = $input.first().json;
const unitPageId = $('Notion — Create Unit Page').item.json.id;

const stepRequests = data.steps.map((step) => ({
  unit_page_id: unitPageId,
  step_title: step.title,
  step_blocks: step.blocks
}));

return stepRequests.map((s) => ({ json: s }));

